#include <Wire.h>
#include <HX711.h>
#include <Adafruit_TCS34725.h>

extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);
extern float mfi_compute(float displacement_mm,float time_s,float orifice_mm2,float density);

HX711 scale;
Adafruit_TCS34725 tcs;
const int SSR_PIN=9,TC_PIN=A0;
const float SP=190.0f,KP=3.0f,KI=0.1f,KD=1.5f,ORIFICE=3.44f,DENSITY=0.92f;
float intg=0,lastE=0;
float lvdt_start=0,test_start_s=0;
bool test_running=false;

// === Barrel Thermocouple ===
void tc_init(){pinMode(TC_PIN,INPUT);}
float tc_read(){return analogRead(TC_PIN)*5.0f/1023.0f*100.0f;}

// === SSR Heater ===
void ssr_init(){pinMode(SSR_PIN,OUTPUT);analogWrite(SSR_PIN,0);}
void ssr_set(int p){analogWrite(SSR_PIN,constrain(p,0,255));}

// === LVDT ===
void lvdt_init(){pinMode(A1,INPUT);}
float lvdt_read(){return analogRead(A1)*10.0f/1023.0f;}

// === Load Cell ===
void scale_init(){scale.begin(5,6);scale.set_scale(2280.0f);scale.tare();}
float scale_read(){return scale.get_units(5);}

// === Colour Sensor ===
bool colour_init(){return tcs.begin();}
float yellowness_index(){uint16_t r,g,b,c;tcs.getRawData(&r,&g,&b,&c);if(c==0)return 0;return(128.0f*r-106.0f*b)/(float)c;}

// === Fault Handler ===
bool fault_check(float temp,float yi){if(temp>250.0f){ssr_set(0);Serial.println("FAULT:OVERTEMP");return true;}if(yi>20.0f){ssr_set(0);Serial.println("FAULT:DEGRADATION");return true;}return false;}

void setup(){
  Serial.begin(115200);Wire.begin();
  tc_init();ssr_init();lvdt_init();scale_init();colour_init();
  Serial.println("t_s,sp,temp,pwm,lvdt,yi,mfi");
}

unsigned long lastMs=0,settled_ms=0;
bool settled=false;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<1.0f)return;lastMs=now;
  float temp=tc_read(),yi=yellowness_index();
  if(fault_check(temp,yi))return;
  int pwm=pid_heater_control(SP,temp,dt,KP,KI,KD,&intg,&lastE);
  ssr_set(pwm);
  if(!settled&&abs(temp-SP)<1.5f){if(settled_ms==0)settled_ms=now;if(now-settled_ms>300000){settled=true;lvdt_start=lvdt_read();test_start_s=now/1000.0f;}}
  float mfi=-1;
  if(settled){float disp=lvdt_read()-lvdt_start;float t_s=now/1000.0f-test_start_s;if(t_s>0)mfi=mfi_compute(disp,t_s,ORIFICE,DENSITY);}
  Serial.print(now/1000);Serial.print(',');Serial.print(SP,0);Serial.print(',');Serial.print(temp,1);Serial.print(',');Serial.print(pwm);Serial.print(',');Serial.print(lvdt_read(),2);Serial.print(',');Serial.print(yi,2);Serial.print(',');Serial.println(mfi,2);
}
